// Vanilla S39PacketPlayerAbilities:
public class S39PacketPlayerAbilities implements Packet<INetHandlerPlayClient> {
    private boolean invulnerable, isFlying, allowFlying, creativeMode;
    private float flySpeed, walkSpeed;
    public S39PacketPlayerAbilities() {}
    public S39PacketPlayerAbilities(PlayerCapabilities caps) {
        this.invulnerable = caps.disableDamage;
        this.isFlying = caps.isFlying;
        this.allowFlying = caps.allowFlying;
        this.creativeMode = caps.isCreativeMode;
        this.flySpeed = caps.getFlySpeed();
        this.walkSpeed = caps.getWalkSpeed();
    }
    public void processPacket(INetHandlerPlayClient h) { h.handlePlayerAbilities(this); }
    public boolean isInvulnerable() { return this.invulnerable; }
    public boolean isFlying() { return this.isFlying; }
    public boolean isAllowFlying() { return this.allowFlying; }
    public boolean isCreativeMode() { return this.creativeMode; }
    public float getFlySpeed() { return this.flySpeed; }
    public float getWalkSpeed() { return this.walkSpeed; }
}
